    def _get_latest_gcs_version(self) -> str:
        try:
            from google.cloud import storage
            
            parsed = urllib.parse.urlparse(self.model_path)
            bucket_name = parsed.netloc
            prefix = parsed.path.lstrip('/')
            
            client = storage.Client()
            bucket = client.bucket(bucket_name)
            blobs = list(bucket.list_blobs(prefix=prefix))
            
            if not blobs:
                raise ValueError(f"No models found at {self.model_path}")
            
            latest_blob = max(blobs, key=lambda b: b.updated)
            return f"gs://{bucket_name}/{latest_blob.name}"
        except ImportError:
            raise ImportError("google-cloud-storage package required for GCS")
    
    def _get_latest_s3_version(self) -> str:
        try:
            import boto3
            
            parsed = urllib.parse.urlparse(self.model_path)
            bucket_name = parsed.netloc
            prefix = parsed.path.lstrip('/')
            
            s3_client = boto3.client('s3')
            response = s3_client.list_objects_v2(Bucket=bucket_name, Prefix=prefix)
            
            if 'Contents' not in response:
                raise ValueError(f"No models found at {self.model_path}")
            
            latest_obj = max(response['Contents'], key=lambda o: o['LastModified'])
            return f"s3://{bucket_name}/{latest_obj['Key']}"
        except ImportError:
            raise ImportError("boto3 package required for S3")
    
    def _get_latest_local_version(self) -> str:
        path = Path(self.model_path)
        
        if path.is_file():
            return str(path)
        
        if path.is_dir():
            model_files = list(path.glob('*.pkl')) + list(path.glob('*.joblib'))
            if not model_files:
                raise ValueError(f"No model files found in {self.model_path}")
            
            latest_file = max(model_files, key=lambda f: f.stat().st_mtime)
            return str(latest_file)
        
        raise ValueError(f"Invalid model path: {self.model_path}")
    
